Select
	ISNULL(Sum(case callresult when 11 then 1 when 21 then 1 else 0 end),0) as totalresponsecnt,
	CONVERT(time(0), DATEADD(SECOND, ISNULL(Sum(case callresult when 11 then SangdamSec when 21 then SangdamSec else 0 end),0), 0)) as mysumcalltime,
	CONVERT(time(0), DATEADD(SECOND, ISNULL(Avg(case callresult when 11 then SangdamSec when 21 then SangdamSec end),0), 0))　as myavgcalltime
From POLARIS.dbo.CDR_${yyyyMM}
Where linetype='01' and callid!=''  and slinum = #{telNum} and sdate = #{yyyyMMdd}

